// Master Transform & Load — detects file type, maps CSV columns to DB schema, builds SQL
const items = $input.all();
const rows = items.map(i => i.json);

if (rows.length === 0) return [{ json: { error: true, file_type: 'empty', row_count: 0, sql: '', message: 'No data rows received' } }];

const cols = Object.keys(rows[0]);
let fileType = 'unknown';
let sql = '';
const rowCount = rows.length;

// Helpers — always convert to String first (Spreadsheet node auto-casts numbers)
const str = (v) => v == null || v === undefined ? '' : String(v).trim();
const esc = (v) => {
    const s = str(v);
    if (s === '') return 'NULL';
    return "'" + s.replace(/'/g, "''") + "'";
};
const num = (v) => {
    const s = str(v);
    if (s === '') return 'NULL';
    const n = parseFloat(s);
    return isNaN(n) ? 'NULL' : n;
};

// ============================================================
// GRADES
// ============================================================
if (cols.some(c => /Student ID/i.test(c)) && cols.some(c => /^Grade$/i.test(c)) && cols.some(c => /Unit Taken/i.test(c))) {
    fileType = 'grades';

    const studentMap = {};
    for (const row of rows) {
        const sid = str(row['Student ID']);
        if (!sid) continue;
        const gpa = parseFloat(str(row['Cumulative GPA']));
        if (!studentMap[sid]) {
            studentMap[sid] = { student_id: sid, name: str(row['Name']), program_code: str(row['Academic Program']), cumulative_gpa: isNaN(gpa) ? 0 : gpa, total_credits_passed: 0 };
        } else {
            if (!isNaN(gpa)) studentMap[sid].cumulative_gpa = gpa;
        }
    }

    for (const row of rows) {
        const sid = str(row['Student ID']);
        if (!sid || !studentMap[sid]) continue;
        const grade = str(row['Grade']);
        const units = parseFloat(str(row['Unit Taken'])) || 0;
        if (!['F', 'FW', 'W', 'U', 'I', 'WF'].includes(grade)) {
            studentMap[sid].total_credits_passed += units;
        }
    }

    const studentVals = Object.values(studentMap).map(s =>
        '(' + esc(s.student_id) + ', ' + esc(s.name) + ', ' + esc(s.program_code) + ', ' + num(s.cumulative_gpa) + ', ' + num(s.total_credits_passed) + ')'
    ).join(',\n');

    sql += 'INSERT INTO students (student_id, name, program_code, cumulative_gpa, total_credits_passed) VALUES\n' + studentVals + '\nON CONFLICT (student_id) DO UPDATE SET name = EXCLUDED.name, program_code = EXCLUDED.program_code, cumulative_gpa = EXCLUDED.cumulative_gpa, total_credits_passed = EXCLUDED.total_credits_passed;\n\n';

    const gradeVals = rows.filter(r => str(r['Student ID'])).map(r =>
        '(' + esc(r['Student ID']) + ', ' + esc(r['Course Code']) + ', ' + esc(r['Term']) + ', ' + esc(r['Grade']) + ', ' + num(r['Term GPA']) + ', ' + num(r['Cumulative GPA']) + ', ' + esc(r['Repeat']) + ', ' + num(r['Unit Taken']) + ')'
    ).join(',\n');

    sql += 'INSERT INTO student_grades (student_id, course_code, term, grade, term_gpa, cumulative_gpa, repeat_flag, unit_taken) VALUES\n' + gradeVals + '\nON CONFLICT (student_id, course_code, term) DO UPDATE SET grade = EXCLUDED.grade, term_gpa = EXCLUDED.term_gpa, cumulative_gpa = EXCLUDED.cumulative_gpa, repeat_flag = EXCLUDED.repeat_flag, unit_taken = EXCLUDED.unit_taken;\n';

// ============================================================
// STUDY PLANS
// ============================================================
} else if (cols.some(c => /^Program$/i.test(c)) && cols.some(c => /^Semester$/i.test(c)) && cols.some(c => /^Course Code$/i.test(c))) {
    fileType = 'study_plan';

    const courseMap = {};
    for (const r of rows) {
        const cc = str(r['Course Code']);
        if (cc && !courseMap[cc]) {
            courseMap[cc] = { course_code: cc, course_name: str(r['Course Name']), credits: r['Credits'], contact_hours: r['Contact Hours'], lec: r['Lec'], tut: r['Tut'], lab: r['Lab'] };
        }
    }

    const courseVals = Object.values(courseMap).map(c =>
        '(' + esc(c.course_code) + ', ' + esc(c.course_name) + ', ' + num(c.credits) + ', ' + num(c.contact_hours) + ', ' + num(c.lec) + ', ' + num(c.tut) + ', ' + num(c.lab) + ')'
    ).join(',\n');

    sql += 'INSERT INTO courses (course_code, course_name, credits, contact_hours, lec_hours, tut_hours, lab_hours) VALUES\n' + courseVals + '\nON CONFLICT (course_code) DO UPDATE SET course_name = EXCLUDED.course_name, credits = EXCLUDED.credits, contact_hours = EXCLUDED.contact_hours, lec_hours = EXCLUDED.lec_hours, tut_hours = EXCLUDED.tut_hours, lab_hours = EXCLUDED.lab_hours;\n\n';

    const planVals = rows.filter(r => str(r['Course Code'])).map(r =>
        '(' + esc(r['Program']) + ', ' + num(r['Semester']) + ', ' + esc(r['Course Code']) + ', ' + num(r['Credits']) + ')'
    ).join(',\n');

    sql += 'INSERT INTO study_plan_entries (program_code, semester_number, course_code, credits) VALUES\n' + planVals + '\nON CONFLICT (program_code, semester_number, course_code) DO UPDATE SET credits = EXCLUDED.credits;\n';

// ============================================================
// PREREQUISITES
// ============================================================
} else if (cols.some(c => /^CourseID$/i.test(c)) && cols.some(c => /^Prerequisite$/i.test(c))) {
    fileType = 'prerequisites';

    const prereqVals = rows.map(r =>
        '(' + esc(r['CourseID']) + ', ' + esc(r['Prerequisite']) + ', ' + esc(r['Condition']) + ')'
    ).join(',\n');

    sql += 'DELETE FROM prerequisites;\nINSERT INTO prerequisites (course_code, prerequisite_code, condition) VALUES\n' + prereqVals + ';\n';

// ============================================================
// ELECTIVES
// ============================================================
} else if (cols.some(c => /Elective Group/i.test(c))) {
    fileType = 'electives';

    const electiveVals = rows.map(r =>
        '(' + esc(r['Program']) + ', ' + esc(r['Elective Group']) + ', ' + esc(r['Course Code']) + ', ' + esc(r['Course Name']) + ')'
    ).join(',\n');

    sql += 'DELETE FROM elective_groups;\nINSERT INTO elective_groups (program_code, group_code, course_code, course_name) VALUES\n' + electiveVals + ';\n';

// ============================================================
// CONSTRAINTS
// ============================================================
} else if (cols.some(c => /Constraint_ID/i.test(c))) {
    fileType = 'constraints';

    const constraintVals = rows.map(r =>
        '(' + esc(r['Constraint_ID']) + ', ' + esc(r['Rule_Name']) + ', ' + num(r['Target_GPA_Min']) + ', ' + num(r['Target_GPA_Max']) + ', ' + num(r['Value']) + ', ' + esc(r['Description']) + ')'
    ).join(',\n');

    sql += 'INSERT INTO constraints (constraint_id, rule_name, gpa_min, gpa_max, value, description) VALUES\n' + constraintVals + '\nON CONFLICT (constraint_id) DO UPDATE SET rule_name = EXCLUDED.rule_name, gpa_min = EXCLUDED.gpa_min, gpa_max = EXCLUDED.gpa_max, value = EXCLUDED.value, description = EXCLUDED.description;\n';

// ============================================================
// ROOMS
// ============================================================
} else if (cols.some(c => /Room_ID/i.test(c))) {
    fileType = 'rooms';

    const roomVals = rows.map(r =>
        '(' + esc(r['Room_ID']) + ', ' + esc(r['Room_Type']) + ', ' + num(r['Capacity']) + ', ' + esc(r['Building']) + ')'
    ).join(',\n');

    sql += 'INSERT INTO rooms (room_id, room_type, capacity, building) VALUES\n' + roomVals + '\nON CONFLICT (room_id) DO UPDATE SET room_type = EXCLUDED.room_type, capacity = EXCLUDED.capacity, building = EXCLUDED.building;\n';
}

if (fileType === 'unknown') {
    return [{ json: { error: true, file_type: 'unknown', row_count: rowCount, sql: '', message: 'Could not detect file type from headers: ' + cols.join(', ') } }];
}

return [{ json: { file_type: fileType, row_count: rowCount, sql: sql, error: false } }];
